SELECT COUNT(*) OVER() AS TOTALCNT ,EMPNO ,ENAME ,JOB FROM EMP
#{endRow}
#{startRow}

SELECT a.comm_grp_cd ,a.comm_grp_cd_nm ,a.comm_grp_cd_expl ,a.use_yn ,a.cd_typ_cd ,DECODE(a.cd_typ_cd,'1','그룹코드','2','일반코드','3','암호코드') cd_typ_nm ,(SELECT b.comm_cd FROM ad_comm_cd b WHERE b.comm_grp_cd = a.comm_grp_cd AND a.cd_typ_cd in ('2','3') AND rownum =1) comm_cd ,TO_CHAR(a.stm_fir_reg_date,'YYYY.MM.DD HH24:MI') stm_fir_reg_date ,a.stm_fir_reg_user_id ,(SELECT NVL(MAX(user_nm),'manual') from ad_user_mst where user_id = a.stm_fir_reg_user_id) stm_fir_reg_user_nm ,TO_CHAR(a.stm_last_upd_date,'YYYY.MM.DD HH24:MI') stm_last_upd_date ,a.stm_last_upd_user_id ,(SELECT NVL(MAX(user_nm),'manual') from ad_user_mst where user_id = a.stm_last_upd_user_id) stm_last_upd_user_nm FROM ad_comm_grp_cd a ,ad_user_mst b WHERE 1=1 AND a.stm_fir_reg_user_id = b.user_id(+)
AND a.comm_grp_cd = #{commGrpCd}
AND a.cd_typ_cd = #{cdTypCd}
AND UPPER(a.comm_grp_cd_nm) LIKE '%' || UPPER(#{commGrpCdNm}) || '%'
AND b.user_nm LIKE '%' || #{userNm} || '%'
ORDER BY a.stm_last_upd_date DESC

