UPDATE ad_comm_cd a
   SET a.cd_expl = #{cdExpl}

      ,a.comm_cd = #{commCd}


      ,a.cd_nm = #{cdNm}


      ,a.cd_val = #{cdVal}

      ,a.use_yn = #{useYn}
      ,a.sort_odr = #{sortOdr}
      ,a.stm_last_upd_date = SYSDATE
      ,a.stm_last_upd_user_id = #{userId}
 WHERE 1=1
   AND a.comm_grp_cd = #{commGrpCd}

   AND a.comm_cd = #{commCd}

mapper.insert:
INSERT INTO ad_comm_cd
(
    comm_grp_cd
    ,comm_cd
    ,cd_nm
    ,cd_val
    ,cd_expl
    ,use_yn
    ,sort_odr
    ,stm_fir_reg_date
    ,stm_fir_reg_user_id
    ,stm_last_upd_date
    ,stm_last_upd_user_id
)
VALUES (
     UPPER(#{commGrpCd})
    ,UPPER(#{commCd})
    ,#{cdNm}
    ,#{cdVal}
    ,#{cdExpl}
    ,#{useYn}


    ,#{sortOdr}


    ,(SELECT NVL(MAX(sort_odr) + 1,1) from ad_comm_cd WHERE comm_grp_cd = #{commGrpCd})


    ,SYSDATE
    ,#{userId}
    ,SYSDATE
    ,#{userId}
)
